for idx, prod in enumerate(products):
    print(f"\n--- Creating product {idx+1}/6: {prod['title'][:40]}...")
    
    # Call the AI generate API
    payload = {
        "product_type": prod["product_type"],
        "title": prod["title"],
        "content": prod["content"],
        "price": prod["price"],
        "seo_keywords": prod["seo_keywords"],
        "requirements": prod["requirements"],
        "version": prod["version"],
        "license": prod["license"],
        "seo_description": prod.get("seo_description", ""),
    }
    
    try:
        result = api_post("/hermes/api/generate", payload)
        pid = result.get("id", "")
        print(f"  ✅ Created ID: {pid}")
        
        # Generate product image
        generate_product_image(prod["title"], pid, prod.get("color", "#a855f7"), prod.get("icon", "📦"))
        
        # Upload the image
        up_result = upload_image(pid)
        if up_result:
            print(f"  ✅ Image uploaded")
        
    except Exception as e:
        print(f"  ❌ Error: {e}")
        import traceback
        traceback.print_exc()

